406 |     /* ── State ── */
407 |     let state = { tasks: [], health: 100, bobVisible: false };
408 | 
409 |     function loadState() {
410 |       try {
411 |         const saved = localStorage.getItem('bob-state');
412 |         if (saved) state = JSON.parse(saved);
413 |       } catch (_) {}
414 |     }
415 | 
416 |     function saveAndBroadcast() {
417 |       localStorage.setItem('bob-state', JSON.stringify(state));
418 |       if (window.electronAPI) window.electronAPI.broadcastState(JSON.stringify(state));
419 |     }
420 | 
421 |     /* ── Health calculation ── */
422 |     function recalcHealth() {
423 |       const tasks = state.tasks;
424 |       if (tasks.length === 0) { state.health = 100; return; }
425 |       const done = tasks.filter(t => t.done).length;
426 |       state.health = Math.round((done / tasks.length) * 100);
427 |     }
428 | 
429 |     /* ── Render ── */
430 |     function render() {
431 |       const list  = document.getElementById('task-list');
432 |       const empty = document.getElementById('empty-msg');
433 |       list.innerHTML = '';
434 | 
435 |       if (state.tasks.length === 0) {
436 |         empty.style.display = 'block';
437 |       } else {
438 |         empty.style.display = 'none';
439 |         state.tasks.forEach((task, idx) => {
440 |           const li = document.createElement('li');
441 |           li.className = 'task-item' + (task.done ? ' done' : '');
442 | 
443 |           // Carbon checkbox
444 |           const cbWrap = document.createElement('label');
445 |           cbWrap.className = 'cds--checkbox-wrapper';
446 |           cbWrap.title = task.done ? 'Mark incomplete' : 'Mark complete';
447 | 
448 |           const cb = document.createElement('input');
449 |           cb.type = 'checkbox';
450 |           cb.className = 'cds--checkbox';
451 |           cb.checked = task.done;
452 |           cb.setAttribute('aria-label', task.text);
453 |           cb.addEventListener('change', () => toggleTask(idx));
454 | 
455 |           const cbAppearance = document.createElement('span');
456 |           cbAppearance.className = 'cds--checkbox-appearance';
457 | 
458 |           cbWrap.appendChild(cb);
459 |           cbWrap.appendChild(cbAppearance);
460 | 
461 |           const label = document.createElement('span');
462 |           label.className = 'task-label';
463 |           label.textContent = task.text;
464 |           label.addEventListener('click', () => toggleTask(idx));
465 | 
466 |           const del = document.createElement('button');
467 |           del.className = 'cds--btn--ghost--icon';
468 |           del.innerHTML = '&#x2715;';
469 |           del.title = 'Delete task';
470 |           del.setAttribute('aria-label', 'Delete: ' + task.text);
471 |           del.addEventListener('click', () => deleteTask(idx));
472 | 
473 |           li.appendChild(cbWrap);
474 |           li.appendChild(label);
475 |           li.appendChild(del);
476 |           list.appendChild(li);
477 |         });
478 |       }
479 | 
480 |       // Health bar
481 |       const pct  = state.health;
482 |       const fill = document.getElementById('health-fill');
483 |       fill.style.width = pct + '%';
484 |       fill.style.background =
485 |         pct > 60 ? '#24a148' : pct > 30 ? '#f1c21b' : '#da1e28';
486 |       document.getElementById('health-label').textContent = 'Bob: ' + pct + '%';
487 |       document.querySelector('[role="progressbar"]').setAttribute('aria-valuenow', pct);
488 | 
489 |       // Toggle button label
490 |       document.getElementById('bob-toggle-btn').textContent =
491 |         state.bobVisible ? 'Hide Bob' : 'Show Bob';
492 | 
493 |       // Bob widget — pose + quip
494 |       updateBobWidget(pct);
495 |     }
496 | 
497 |     /* ── Bob widget ── */
498 |     const BOB_QUIPS = {
499 |       happy:   ['You\'re crushing it!', 'Tasks done = Bob happy!', 'Keep up the great work!', 'Productivity level: max!', 'Look at you go!'],
500 |       neutral: ['Almost there!', 'A few more tasks to go.', 'You\'ve got this.', 'Steady progress.', 'Half way there!'],
501 |       sad:     ['I believe in you\u2026', 'Please complete some tasks!', 'I need those checkmarks\u2026', 'Don\'t give up on me!', 'Tasks = my life force.'],
502 |     };
503 |     let _lastQuip = '';
504 | 
505 |     function updateBobWidget(pct) {
506 |       const mood   = pct > 60 ? 'happy' : pct > 30 ? 'neutral' : 'sad';
507 |       const sprite = document.getElementById('bob-sprite');
508 |       const wrap   = document.getElementById('bob-sprite-wrap');
509 | 
510 |       // Quip — pick a new one from the right mood pool
511 |       const pool = BOB_QUIPS[mood];
512 |       let quip   = pool[Math.floor(Math.random() * pool.length)];
513 |       // avoid repeating the same quip twice in a row
514 |       if (quip === _lastQuip && pool.length > 1) quip = pool[(pool.indexOf(quip) + 1) % pool.length];
515 |       _lastQuip = quip;
516 |       document.getElementById('bob-quip').textContent = quip;
517 |     }
518 | 
519 |     /* Rotate quip every 10 s */
520 |     setInterval(() => updateBobWidget(state.health), 10000);
521 | 
522 |     /* ── Actions ── */
523 |     function addTask(text) {
524 |       text = text.trim();
525 |       if (!text) return;
526 |       state.tasks.push({ id: Date.now(), text, done: false });
527 |       recalcHealth();
528 |       saveAndBroadcast();
529 |       render();
530 |     }
531 | 
532 |     function toggleTask(idx) {
533 |       state.tasks[idx].done = !state.tasks[idx].done;
534 |       recalcHealth();
535 |       saveAndBroadcast();
536 |       render();
537 |     }
538 | 
539 |     function deleteTask(idx) {
540 |       state.tasks.splice(idx, 1);
541 |       recalcHealth();
542 |       saveAndBroadcast();
543 |       render();
544 |     }
