546 |     /* ── UI events ── */
547 |     document.getElementById('add-btn').addEventListener('click', () => {
548 |       const input = document.getElementById('new-task-input');
549 |       addTask(input.value);
550 |       input.value = '';
551 |       input.focus();
552 |     });
553 | 
554 |     document.getElementById('new-task-input').addEventListener('keydown', e => {
555 |       if (e.key === 'Enter') {
556 |         addTask(e.target.value);
557 |         e.target.value = '';
558 |       }
559 |     });
560 | 
561 |     document.getElementById('bob-toggle-btn').addEventListener('click', () => {
562 |       state.bobVisible = !state.bobVisible;
563 |       if (window.electronAPI) {
564 |         if (state.bobVisible) window.electronAPI.openBobPopup();
565 |         else window.electronAPI.closeBobPopup();
566 |       }
567 |       saveAndBroadcast();
568 |       render();
569 |     });
570 | 
571 |     /* ── IPC sync from Bob popup ── */
572 |     if (window.electronAPI) {
573 |       window.electronAPI.onBobClosed(() => {
574 |         state.bobVisible = false;
575 |         render();
576 |       });
577 |       window.electronAPI.onStateSync(json => {
578 |         try { state = JSON.parse(json); } catch (_) {}
579 |         render();
580 |       });
581 |     }
