      ctx.fillStyle = '#ffd6a5';
      roundRect(ctx, 25, 5, 40, 36, 14);
      ctx.fill();

      // eyes
      ctx.fillStyle = '#161616';
      ctx.beginPath();
      ctx.arc(36, 20, 4, 0, Math.PI * 2);
      ctx.arc(54, 20, 4, 0, Math.PI * 2);
      ctx.fill();

      // eye highlights
      ctx.fillStyle = '#fff';
      ctx.beginPath();
      ctx.arc(38, 18, 1.5, 0, Math.PI * 2);
      ctx.arc(56, 18, 1.5, 0, Math.PI * 2);
      ctx.fill();

