<body>
  <header>
    <h1>IBM Bob Notepad</h1>
    <div id="bob-health-bar">
      <span id="health-label">Bob: 100%</span>
      <div id="health-track"><div id="health-fill" style="width:100%"></div></div>
    </div>
    <button id="bob-toggle-btn">Show Bob</button>
  </header>

  <div id="add-row">
    <input id="new-task-input" type="text" placeholder="Add a new task…" autocomplete="off" />
    <button id="add-btn">Add</button>
  </div>

  <div id="task-list-wrapper">
    <ul id="task-list"></ul>
    <p id="empty-msg">No tasks yet. Add one above!</p>
  </div>

  <script>
    /* ── State ── */
    let state = { tasks: [], health: 100, bobVisible: false };

    function loadState() {
      try {
        const saved = localStorage.getItem('bob-state');
        if (saved) state = JSON.parse(saved);
      } catch (_) {}
    }

    function saveAndBroadcast() {
      localStorage.setItem('bob-state', JSON.stringify(state));
      if (window.electronAPI) window.electronAPI.broadcastState(JSON.stringify(state));
    }

    /* ── Health calculation ── */
    function recalcHealth() {
      const tasks = state.tasks;
      if (tasks.length === 0) { state.health = 100; return; }
      const done = tasks.filter(t => t.done).length;
      state.health = Math.round((done / tasks.length) * 100);
    }

    /* ── Render ── */
    function render() {
      const list = document.getElementById('task-list');
      const empty = document.getElementById('empty-msg');
      list.innerHTML = '';

      if (state.tasks.length === 0) {
        empty.style.display = 'block';
      } else {
        empty.style.display = 'none';
        state.tasks.forEach((task, idx) => {
          const li = document.createElement('li');
          li.className = 'task-item' + (task.done ? ' done' : '');

          const cb = document.createElement('input');
          cb.type = 'checkbox';
          cb.checked = task.done;
          cb.addEventListener('change', () => { toggleTask(idx); });

          const label = document.createElement('span');
          label.className = 'task-label';
          label.textContent = task.text;
          label.addEventListener('click', () => { toggleTask(idx); });

          const del = document.createElement('button');
          del.className = 'delete-btn';
          del.textContent = '×';
          del.title = 'Delete task';
          del.addEventListener('click', () => { deleteTask(idx); });

          li.appendChild(cb);
          li.appendChild(label);
          li.appendChild(del);
          list.appendChild(li);
        });
      }

      // Update health bar
      const pct = state.health;
      const fill = document.getElementById('health-fill');
      fill.style.width = pct + '%';
      fill.style.background = pct > 60 ? '#42be65' : pct > 30 ? '#f1c21b' : '#da1e28';
      document.getElementById('health-label').textContent = 'Bob: ' + pct + '%';

      // Bob toggle button label
      document.getElementById('bob-toggle-btn').textContent =
        state.bobVisible ? 'Hide Bob' : 'Show Bob';
    }

    /* ── Actions ── */
    function addTask(text) {
      text = text.trim();
      if (!text) return;
      state.tasks.push({ id: Date.now(), text, done: false });
      recalcHealth();
      saveAndBroadcast();
      render();
    }

    function toggleTask(idx) {
      state.tasks[idx].done = !state.tasks[idx].done;
      recalcHealth();
      saveAndBroadcast();
      render();
    }

    function deleteTask(idx) {
      state.tasks.splice(idx, 1);
      recalcHealth();
      saveAndBroadcast();
      render();
    }

    /* ── UI events ── */
    document.getElementById('add-btn').addEventListener('click', () => {
      const input = document.getElementById('new-task-input');
      addTask(input.value);
      input.value = '';
    });

    document.getElementById('new-task-input').addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        const input = e.target;
        addTask(input.value);
        input.value = '';
      }
    });

    document.getElementById('bob-toggle-btn').addEventListener('click', () => {
      state.bobVisible = !state.bobVisible;
      if (window.electronAPI) {
        if (state.bobVisible) window.electronAPI.openBobPopup();
        else window.electronAPI.closeBobPopup();
      }
      saveAndBroadcast();
      render();
    });

    /* ── IPC sync from Bob popup ── */
    if (window.electronAPI) {
      window.electronAPI.onStateSync(json => {
        try { state = JSON.parse(json); } catch (_) {}
        render();
      });
    }

    /* ── Boot ── */
    loadState();
    render();
  </script>
</body>
